    // Create edges to connect the nodes
    make_edge(producer, processor);  // Connect producer to processor
    make_edge(processor, consumer);   // Connect processor to consumer

    // Supply inputs to the producer
    for (int i = 1; i <= 5; ++i) {
        producer.try_put(i); // Try to put integers to be processed
